import{c as e,Q as t,j as n,m as s}from"./chunks/framework.D9IbVcwA.js";const b=JSON.parse('{"title":"029-gui-canvas-1 · GUI Canvas","description":"","frontmatter":{"title":"029-gui-canvas-1 · GUI Canvas"},"headers":[],"relativePath":"hands-on/029-gui-canvas-1.md","filePath":"hands-on/029-gui-canvas-1.md","lastUpdated":1779686691000}'),r={name:"hands-on/029-gui-canvas-1.md"};function i(o,a,d,p,c,l){return t(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="framebuffer-接口与-canvas-双缓冲架构设计" tabindex="-1">Framebuffer 接口与 Canvas 双缓冲架构设计 <a class="header-anchor" href="#framebuffer-接口与-canvas-双缓冲架构设计" aria-label="Permalink to &quot;Framebuffer 接口与 Canvas 双缓冲架构设计&quot;">​</a></h1><blockquote><p>标签：framebuffer, canvas, double buffering, pitch, 2D graphics 前置：<a href="./028e-activate-init-thread-3">028e init 线程</a></p></blockquote><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>到目前为止，我们内核的图形输出方式还停留在「直接写 framebuffer」的阶段——Console 驱动调用 <code>Framebuffer::put_pixel()</code>，每次写入都直接抵达硬件显存。这种做法在小规模文字输出时够用，但一旦我们想在屏幕上画复杂的图形（矩形、线条、文字组合），问题就来了：用户会看到画面撕裂，因为显示控制器在扫描输出的过程中，我们可能正在写入同一块显存，半新半旧的像素就出现在了屏幕上。</p><p>本章我们要构建一个完整的 2D 图形画布——Canvas。它采用经典的软件双缓冲方案：所有绘制操作都在一个离屏的后备缓冲区（back buffer）上完成，画完一整帧后一次性拷贝到硬件 framebuffer。这是所有 GUI 系统的基本功——不管你是 Linux 的 fbdev、SerenityOS 的 LibGfx，还是更早期的 Windows GDI，双缓冲都是绕不过去的第一步。</p><p>完成本章后，我们会在屏幕上看到通过 Canvas 绘制的彩色矩形和标题文字——这是我们 GUI 子系统的起点。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="为什么需要-framebuffer-抽象层" tabindex="-1">为什么需要 Framebuffer 抽象层 <a class="header-anchor" href="#为什么需要-framebuffer-抽象层" aria-label="Permalink to &quot;为什么需要 Framebuffer 抽象层&quot;">​</a></h3><p>在 tag 013 里，我们写了一个直接操作 VBE linear framebuffer 的驱动。那个驱动把 bootloader 传来的物理地址映射到内核虚拟地址空间，然后提供 <code>put_pixel()</code> 和 <code>fill_rect()</code> 等接口。现在我们想做 GUI 了，直接操作 framebuffer 的问题就暴露出来了：每次写像素都要走 MMIO（memory-mapped I/O），速度慢；更关键的是没法实现双缓冲——你没法在「另一个 framebuffer」上画完了再切换过去，因为硬件只认一个物理地址。</p><p>所以我们引入了一层抽象：Canvas 类。Canvas 不直接操作硬件 framebuffer，而是持有一个在内核堆上分配的 <code>uint32_t</code> 数组作为后备缓冲区。Canvas 对外暴露的绘图 API（draw_pixel、draw_rect、draw_line 等）全部写这个后备缓冲区。当一帧画完后，调用 <code>flip()</code> 方法，把后备缓冲区的内容按行拷贝到硬件 framebuffer。</p><h3 id="pitch-的概念" tabindex="-1">pitch 的概念 <a class="header-anchor" href="#pitch-的概念" aria-label="Permalink to &quot;pitch 的概念&quot;">​</a></h3><p>这里有一个很多人第一次接触 framebuffer 编程时都会踩的坑：<strong>pitch 不等于 width * 4</strong>。pitch 是「每条扫描线占用的字节数」，在某些 VBE 模式下，硬件为了对齐或其他原因，会在每行末尾加 padding。比如 1024x768 的 32 位色模式，理论上每行是 1024 * 4 = 4096 字节，但有些硬件的 pitch 可能是 4128 字节。如果你用 <code>width * 4</code> 来计算像素偏移，在第一行没问题，但到了第二行开始就会偏移——画面会出现「倾斜」效果。</p><p>Canvas 在初始化时从 Framebuffer 获取 pitch，后续所有像素索引计算都使用 <code>pitch / 4</code>（每个 uint32_t 占 4 字节），而不是直接用 width。这就是为什么我们的 back buffer 的大小是 <code>(pitch / 4) * height</code> 个 uint32_t，而不是简单的 <code>width * height</code>。</p><h3 id="双缓冲的内存模型" tabindex="-1">双缓冲的内存模型 <a class="header-anchor" href="#双缓冲的内存模型" aria-label="Permalink to &quot;双缓冲的内存模型&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+--------------------+         +--------------------+</span></span>
<span class="line"><span>|   Back Buffer      |  flip() |  Front Buffer      |</span></span>
<span class="line"><span>|   (kernel heap)    | -------&gt;|  (MMIO framebuffer)|</span></span>
<span class="line"><span>|   可随意读写       |  memcpy |  volatile, 只写    |</span></span>
<span class="line"><span>+--------------------+         +--------------------+</span></span>
<span class="line"><span>      draw_pixel()</span></span>
<span class="line"><span>      draw_rect()</span></span>
<span class="line"><span>      draw_line()</span></span>
<span class="line"><span>      draw_text()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>后备缓冲区是普通的内核堆内存，读写毫无限制。前缓冲区是 MMIO 映射的硬件显存，需要用 volatile 指针访问，并且拷贝时要逐行处理（因为 pitch 可能和 width 不对齐）。</p><h3 id="与-linux-fbdev-的对比" tabindex="-1">与 Linux fbdev 的对比 <a class="header-anchor" href="#与-linux-fbdev-的对比" aria-label="Permalink to &quot;与 Linux fbdev 的对比&quot;">​</a></h3><p>Linux 的 fbdev 子系统也采用类似的双缓冲方案。用户程序通过 <code>mmap()</code> 把 <code>/dev/fb0</code> 映射到用户空间作为前缓冲区，然后自己 <code>malloc</code> 一块内存作为后缓冲区。画完后要么 <code>memcpy</code> 过去，要么用 <code>FBIOPAN_DISPLAY</code> ioctl 让硬件切换扫描地址（page flip）。Cinux 的做法等价于前者的 <code>memcpy</code> 方案——简单、通用、不依赖硬件特性。Linux 的现代 DRM/KMS 子系统则提供了更高效的 atomic page flip，但那需要一个完整的 GPU 驱动程序，对我们的教学内核来说太重了。</p><h3 id="volatile-关键字在-mmio-中的作用" tabindex="-1">volatile 关键字在 MMIO 中的作用 <a class="header-anchor" href="#volatile-关键字在-mmio-中的作用" aria-label="Permalink to &quot;volatile 关键字在 MMIO 中的作用&quot;">​</a></h3><p>在 Canvas 的实现中，你会频繁看到 <code>volatile</code> 关键字。这不是摆设——它是正确性的保证。C++ 编译器被允许做很多优化，其中之一是「冗余存储消除」：如果你对同一个地址写了两次，编译器认为第一次的写入被第二次覆盖了，可以省略第一次。对于普通内存这是正确的优化，但对于 MMIO 设备寄存器，两次写入可能代表两个不同的命令——省略任何一个都会导致硬件行为错误。</p><p>在 <code>flip()</code> 中，我们把 back buffer 的数据拷贝到 <code>volatile uint8_t*</code>（framebuffer 地址）。volatile 告诉编译器「这个内存位置的值可能在你的控制之外改变，不要对它的读写做任何假设」。这保证了每次 <code>d[i] = s[i]</code> 都会生成一次真正的存储指令，不会被优化掉或合并。在我们的自定义 <code>memcopy()</code> 函数中，目标参数类型就是 <code>volatile void*</code>——这就是为什么我们不能用标准 <code>memcpy</code>（它的参数不是 volatile 的）。</p><h3 id="canvas-的两种初始化模式" tabindex="-1">Canvas 的两种初始化模式 <a class="header-anchor" href="#canvas-的两种初始化模式" aria-label="Permalink to &quot;Canvas 的两种初始化模式&quot;">​</a></h3><p>Canvas 提供了两种初始化方式，这并不是多余的——它们服务于不同的使用场景。<code>init(Framebuffer&amp;)</code> 创建「屏幕 Canvas」，它有一个硬件前缓冲区，flip 会把内容刷新到真实的显示器上。<code>init(uint32_t w, uint32_t h)</code> 创建「离屏 Canvas」，没有硬件前缓冲区，flip 是空操作——画完的内容只存在于内存中，需要通过 blit 拷贝到屏幕 Canvas 才能显示。</p><p>为什么需要离屏 Canvas？想象一下窗口管理器的场景：每个窗口在自己的离屏 Canvas 上绘制内容（标题栏、按钮、文字），窗口管理器把所有窗口的内容合成到屏幕 Canvas 上，最后 flip 显示。这种「各自画自己的，最后合成」的架构是所有 GUI 系统的基本模式——从 X11 到 Wayland 到 Windows 都是这么做的。离屏 Canvas 就是窗口的「私有画布」。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-扩展-framebuffer-接口" tabindex="-1">Step 1: 扩展 Framebuffer 接口 <a class="header-anchor" href="#step-1-扩展-framebuffer-接口" aria-label="Permalink to &quot;Step 1: 扩展 Framebuffer 接口&quot;">​</a></h3><p><strong>目标</strong>: 在 <code>Framebuffer</code> 类中添加一个 <code>data()</code> 方法，返回 framebuffer 的原始内存指针。</p><p><strong>设计思路</strong>: Canvas 的 <code>flip()</code> 需要直接访问 framebuffer 的原始内存来执行批量拷贝。之前 Framebuffer 的 <code>put_pixel()</code> 是唯一的写入接口，但它逐像素操作太慢了。我们添加 <code>data()</code> 返回 <code>volatile uint32_t*</code>，让 Canvas 可以做行级的 memcpy。注意返回类型是 volatile 的，因为 framebuffer 是 MMIO 设备内存。</p><p><strong>实现约束</strong>: 返回类型为 <code>volatile uint32_t*</code>。这个方法只是 getter，不修改任何状态。</p><p><strong>验证</strong>: 添加后编译通过即可。功能验证在 Canvas 集成时进行。</p><h3 id="step-2-设计-canvas-类" tabindex="-1">Step 2: 设计 Canvas 类 <a class="header-anchor" href="#step-2-设计-canvas-类" aria-label="Permalink to &quot;Step 2: 设计 Canvas 类&quot;">​</a></h3><p><strong>目标</strong>: 创建 Canvas 类的头文件，定义所有必要的字段和方法签名。</p><p><strong>设计思路</strong>: Canvas 需要两个核心数据——一个指向硬件 Framebuffer 的指针（front_buf_）和一个自己分配的后备缓冲区（back_buf_）。它还需要 width、height、pitch 三个维度信息来正确计算像素偏移。方法方面，我们需要：初始化（从 Framebuffer 或指定尺寸）、基本绘制（pixel、rect、line）、文字渲染（text）、缓冲区操作（flip、clear）。</p><p>一个重要的设计决策是提供两种初始化方式：<code>init(Framebuffer&amp;)</code> 用于屏幕 Canvas（有前缓冲区，flip 会真正刷新屏幕），<code>init(uint32_t w, uint32_t h)</code> 用于离屏 Canvas（没有前缓冲区，flip 是空操作）。后者在后续的窗口系统中会大量使用——每个窗口有自己的离屏 Canvas。</p><p><strong>实现约束</strong>: 禁止拷贝构造和拷贝赋值（因为内部有动态分配的缓冲区）。析构函数需要释放 back_buf_。所有方法都不应该是虚函数——我们不打算继承 Canvas，保持简单。</p><p><strong>踩坑预警</strong>: back_buf_ 的分配大小必须是 <code>(pitch / 4) * height</code> 而不是 <code>width * height</code>。如果你用后者，在 pitch &gt; width<em>4 的硬件上会越界写入，导致内核堆损坏。这是非常隐蔽的 bug——在 QEMU 里可能不会触发（QEMU 的 pitch 通常等于 width</em>4），但在真机或某些模拟器上会崩溃。</p><p><strong>验证</strong>: 编译通过。后续步骤中会添加具体实现。</p><h3 id="step-3-实现-canvas-初始化与基本像素操作" tabindex="-1">Step 3: 实现 Canvas 初始化与基本像素操作 <a class="header-anchor" href="#step-3-实现-canvas-初始化与基本像素操作" aria-label="Permalink to &quot;Step 3: 实现 Canvas 初始化与基本像素操作&quot;">​</a></h3><p><strong>目标</strong>: 实现 <code>init()</code>、<code>draw_pixel()</code>、<code>clear()</code> 方法。</p><p><strong>设计思路</strong>: <code>init(Framebuffer&amp;)</code> 从 Framebuffer 获取维度信息，分配后备缓冲区，用 memfill32 清零。<code>draw_pixel()</code> 做边界检查后写入 <code>back_buf_[y * (pitch/4) + x]</code>。<code>clear()</code> 用 memfill32 把整个后备缓冲区填充为指定颜色。</p><p>这里我们写了两个内部辅助函数：<code>memcopy()</code> 用于 volatile 目标的字节拷贝（替代 libc memcpy，因为内核是 freestanding 的），<code>memfill32()</code> 用于用 32 位值填充一段内存（比逐字节填充快 4 倍）。</p><p><strong>实现约束</strong>: memcopy 的目标参数必须是 volatile void*，因为前缓冲区是 MMIO。分配后备缓冲区时用 <code>new uint32_t[total_pixels]</code>，这会走内核堆的 operator new。如果堆空间不足（例如只有 64KB 初始堆），你需要先确保堆的 max_size_ 足够大。</p><p><strong>踩坑预警</strong>: Canvas 的 back buffer 大约需要 <code>width * height * 4</code> 字节。对于 1024x768，就是大约 3MB。如果你的内核堆只预留了 1MB 的虚拟地址空间，<code>new</code> 会触发 expand，然后 expand 发现没有上限检查就会一直扩展，最终覆盖到 MMIO 或栈的虚拟地址区域。这个坑我们在后面的第三篇文章中会详细讨论。</p><p><strong>验证</strong>: 编译后运行，检查串口输出 <code>[HEAP] Expanded by ...</code> 日志。如果看到 <code>[HEAP] Expansion limit reached</code>，说明堆空间不足。</p><h3 id="step-4-实现-flip-方法" tabindex="-1">Step 4: 实现 flip() 方法 <a class="header-anchor" href="#step-4-实现-flip-方法" aria-label="Permalink to &quot;Step 4: 实现 flip() 方法&quot;">​</a></h3><p><strong>目标</strong>: 把后备缓冲区的内容拷贝到硬件 framebuffer。</p><p><strong>设计思路</strong>: flip() 逐行拷贝——对于每一行，计算前缓冲区中该行的起始地址（考虑 pitch），然后用 memcopy 拷贝 width<em>4 字节。注意只拷贝 width</em>4 而不是 pitch 字节——pitch 可能包含 padding 字节，那些不需要从 back buffer 拷贝（它们可能包含硬件状态信息）。</p><p><strong>实现约束</strong>: 如果 front_buf_ 为 nullptr（离屏 Canvas），flip() 应该直接返回不做任何事。back_buf_ 为 nullptr 时同理。</p><p><strong>验证</strong>: 编写一个简单的测试：init Canvas、draw 一个矩形、flip、然后检查 framebuffer 上对应位置的像素值是否正确。我们会在后面的测试步骤中详细展示。</p><h3 id="step-5-内核测试验证" tabindex="-1">Step 5: 内核测试验证 <a class="header-anchor" href="#step-5-内核测试验证" aria-label="Permalink to &quot;Step 5: 内核测试验证&quot;">​</a></h3><p><strong>目标</strong>: 编写内核态测试，验证 Canvas 初始化和基本绘制操作的正确性。</p><p><strong>设计思路</strong>: 测试分两个模式——CLI 模式（始终编译）验证 Framebuffer 和 Font 基本可用性，GUI 模式（CINUX_GUI 宏控制）验证 Canvas 的初始化、draw_rect、clear、flip。测试的核心思路是：在 Canvas 上画一个已知颜色的矩形，flip 后通过 Framebuffer 的 <code>get_pixel()</code> 读取硬件 framebuffer 的对应位置，确认像素值和预期一致。这是一种「写入-刷新-读回验证」的闭环测试。</p><p>对于 CLI 模式的测试，我们需要验证即使不编译 Canvas，Framebuffer 的基本功能（put_pixel、get_pixel、fill_rect、clear）仍然正常工作。这保证了 GUI 代码是真正可选的——关闭 CINUX_GUI 后内核行为不变。</p><p><strong>实现约束</strong>: 测试函数通过 <code>run_canvas_tests()</code> 入口调用。每个测试用 TEST_ASSERT_EQ/TEST_ASSERT_GT 等宏检查条件。测试中创建的 Canvas 是栈变量，析构时自动释放 back buffer。</p><p><strong>验证</strong>: 运行内核，检查串口输出。CLI 模式应该看到三个测试全部 PASS。GUI 模式应该额外看到 Canvas GUI Tests 全部 PASS。</p><h3 id="step-6-主机端单元测试" tabindex="-1">Step 6: 主机端单元测试 <a class="header-anchor" href="#step-6-主机端单元测试" aria-label="Permalink to &quot;Step 6: 主机端单元测试&quot;">​</a></h3><p><strong>目标</strong>: 编写可以在 Linux 主机上编译运行的单元测试，不依赖内核环境。</p><p><strong>设计思路</strong>: 主机端测试使用 mock 对象模拟 Framebuffer 和 PSFFont。MockFramebuffer 用 std::vector 分配像素数组，提供和内核 Framebuffer 相同的接口。MockPSFFont 允许手动设置字形位图数据。MockCanvas 复制了 Canvas 的全部算法逻辑。测试覆盖所有绘制方法：draw_pixel、draw_rect、draw_rect_outline、clear、flip、draw_line、draw_text、blit、draw_bitmap。</p><p>这种「在主机上用 mock 测试内核算法」的模式非常有价值——编译速度快（秒级 vs. 内核编译的分钟级），可以用 GDB 调试，不需要启动 QEMU。唯一需要注意的是 mock 的行为必须和内核实现完全一致——如果 mock 和内核代码有差异，测试通过不代表内核代码正确。</p><p><strong>实现约束</strong>: 使用 <code>#ifdef CINUX_HOST_TEST</code> 条件编译。测试文件放在 <code>test/unit/test_canvas.cpp</code>。CMakeLists.txt 中添加编译配置。</p><p><strong>验证</strong>: 在主机上编译并运行测试：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd test &amp;&amp; mkdir build &amp;&amp; cd build</span></span>
<span class="line"><span>cmake .. &amp;&amp; make &amp;&amp; ./test_canvas</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>所有测试应该 PASS。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>在启用 GUI 模式的情况下构建：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mkdir -p build &amp;&amp; cd build</span></span>
<span class="line"><span>cmake .. -DCINUX_GUI=ON &amp;&amp; make -j$(nproc)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>运行 QEMU：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>qemu-system-x86_64 -cdrom cinux.iso -serial stdio -no-reboot</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你应该在 QEMU 窗口中看到黑色屏幕（Canvas 已初始化但还没画东西），串口输出中会看到 <code>[HEAP] Expanded by ...</code> 和 <code>[BIG] GUI Canvas initialised: 1024x768</code> 等日志。</p><p>如果你想在不启用 GUI 的情况下验证内核仍然正常工作：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmake .. -DCINUX_GUI=OFF &amp;&amp; make -j$(nproc)</span></span>
<span class="line"><span>./run.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>此时应该只看到 CLI 模式的测试通过，Canvas GUI Tests 被跳过。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>最常见的 bug：画面倾斜或花屏</strong>。这说明你的像素偏移计算有问题——检查是否用了 <code>width</code> 而不是 <code>pitch/4</code> 来计算行偏移。在 Canvas 的任何地方，像素索引都必须是 <code>y * (pitch / 4) + x</code>。</p><p><strong>第二个常见问题：flip 后屏幕全黑</strong>。检查 draw_pixel 和 draw_rect 是否真的写入了 back buffer。可以在 draw 操作后加一个临时的串口日志，打印某个像素位置的值。</p><p><strong>用 QEMU monitor 调试</strong>：按 Ctrl+A 然后按 C 进入 QEMU monitor，输入 <code>info mtree</code> 可以看到 framebuffer 的内存映射情况，确认物理地址和虚拟地址映射是否正确。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>说明</th></tr></thead><tbody><tr><td>Double Buffering</td><td>后备缓冲区绘制 + flip 一次性刷新</td></tr><tr><td>pitch</td><td>每条扫描线的字节数，可能大于 width * bytes_per_pixel</td></tr><tr><td>volatile MMIO</td><td>framebuffer 是设备内存，需要 volatile 指针访问</td></tr><tr><td>Back buffer</td><td>内核堆上的 uint32_t 数组，大小为 (pitch/4) * height</td></tr><tr><td>Front buffer</td><td>Framebuffer.data() 返回的 volatile 指针</td></tr></tbody></table><p>到这里我们已经搭好了 Canvas 的骨架——初始化、像素操作和双缓冲翻转都就位了。下一章我们来实现更高级的图元绘制：直线（Bresenham）、矩形描边、位图渲染和画布间 blit 操作。</p><h2 id="概念补充-为什么内核需要自己的-memcopy" tabindex="-1">概念补充：为什么内核需要自己的 memcopy <a class="header-anchor" href="#概念补充-为什么内核需要自己的-memcopy" aria-label="Permalink to &quot;概念补充：为什么内核需要自己的 memcopy&quot;">​</a></h2><p>你可能会问：为什么不直接用 <code>memcpy</code> 或者 <code>memset</code>？答案在于两点。首先，Cinux 内核是 freestanding 环境——没有 libc，没有标准库函数。虽然 GCC 可能会生成对 <code>memcpy</code> 的隐式调用（比如结构体赋值时），但我们显式使用的拷贝函数必须自己实现。其次，<code>memcopy</code> 的目标参数是 <code>volatile void*</code>——标准 <code>memcpy</code> 的签名不接受 volatile 指针。如果我们把 volatile 指针强转为 <code>void*</code> 传给 <code>memcpy</code>，编译器可能对写入 MMIO 的操作做「合法」的优化（比如合并连续写入），导致画面显示不正确。</p><p><code>memfill32</code> 按整个 uint32_t 填充而不是逐字节填充，这在 32 位色模式下天然正确——每个像素就是一个 uint32_t。相比逐字节填充，这减少了 4 倍的循环迭代次数。对于 3MB 的 back buffer（约 786432 个 uint32_t），这就是 786432 次 vs. 3145728 次循环迭代的差距。</p><h2 id="设计决策总结" tabindex="-1">设计决策总结 <a class="header-anchor" href="#设计决策总结" aria-label="Permalink to &quot;设计决策总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>决策点</th><th>我们的选择</th><th>备选方案</th><th>理由</th></tr></thead><tbody><tr><td>后备缓冲区位置</td><td>内核堆 (new[])</td><td>固定物理地址</td><td>堆分配灵活，大小随分辨率自适应</td></tr><tr><td>前缓冲区指针</td><td>volatile uint32_t*</td><td>封装为 Framebuffer 方法</td><td>批量操作需要原始指针，put_pixel 太慢</td></tr><tr><td>离屏 Canvas</td><td>init(w, h) 无 front</td><td>只支持屏幕 Canvas</td><td>窗口系统需要独立的离屏渲染面</td></tr><tr><td>拷贝函数</td><td>自定义 memcopy</td><td>libc memcpy</td><td>volatile 支持和 freestanding 环境</td></tr><tr><td>像素格式</td><td>固定 0x00RRGGBB</td><td>可配置格式</td><td>简化实现，VBE 32 位色模式统一</td></tr></tbody></table>`,84)])])}const h=e(r,[["render",i]]);export{b as __pageData,h as default};
